                                   KEY `idx_route_id` (`route_id`),
                                   KEY `idx_point_id` (`point_id`)
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='路线点位关联表';

