-- ----------------------------
-- Table structure for sys_tour_content
-- ----------------------------
DROP TABLE IF EXISTS `sys_tour_content`;
CREATE TABLE `sys_tour_content`  (
  `content_id` int NOT NULL AUTO_INCREMENT COMMENT '内容ID',
  `robot_id` int NOT NULL COMMENT '机器人ID',
  `point_id` int NULL DEFAULT NULL COMMENT '关联点位ID',
  `point_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '讲解点名称',
  `point_desc` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '讲解点描述',
  `broadcast_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'text' COMMENT '播报类型(text文本/audio音频)',
  `broadcast_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '播报内容',
  `audio_file` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '音频文件路径',
  `voice_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '温柔女声' COMMENT '音色',
  `speech_rate` int NULL DEFAULT 50 COMMENT '语速(%)',
  `interval_time` int NULL DEFAULT 0 COMMENT '间隔时间(毫秒)',
  `content_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'text' COMMENT '内容类型(text/audio/image/video)',
  `media_file` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '媒体文件路径',
  `arm_action` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0掳' COMMENT '手臂动作',
  `chassis_angle` int NULL DEFAULT 0 COMMENT '底盘转角',
  `order_num` int NULL DEFAULT 0 COMMENT '显示顺序',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `tenant_id` bigint NULL DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`content_id`) USING BTREE,
  INDEX `idx_robot_id`(`robot_id` ASC) USING BTREE,
  INDEX `idx_point_id`(`point_id` ASC) USING BTREE,
  INDEX `idx_sys_tour_content_tenant`(`tenant_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '讲解内容表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_tour_content
-- ----------------------------

-- ----------------------------
-- Table structure for sys_tour_general
-- ----------------------------
DROP TABLE IF EXISTS `sys_tour_general`;
CREATE TABLE `sys_tour_general`  (
  `config_id` int NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `robot_id` int NOT NULL COMMENT '机器人ID',
  `map_id` int NULL DEFAULT NULL COMMENT '当前地图ID',
  `route_id` int NULL DEFAULT NULL COMMENT '当前路线ID',
  `voice` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '温柔女声' COMMENT '讲解音色',
  `voice_interaction` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '1' COMMENT '语音交互（0关闭 1开启）',
  `start_command` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '开始讲解' COMMENT '开始讲解口令',
  `before_tip` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '运动前提示播报',
  `end_tip` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '讲解结束播报',
  `after_action` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'stay' COMMENT '结束后动作(stay停留/charge充电)',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `tenant_id` bigint NULL DEFAULT NULL COMMENT '租户ID',
  PRIMARY KEY (`config_id`) USING BTREE,
  INDEX `idx_robot_id`(`robot_id` ASC) USING BTREE,
  INDEX `idx_sys_tour_general_tenant`(`tenant_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '讲解通用配置表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_tour_general
-- ----------------------------

-- ----------------------------
-- Table structure for sys_tour_route
-- ----------------------------
DROP TABLE IF EXISTS `sys_tour_route`;
CREATE TABLE `sys_tour_route` (
                                  `route_id` int NOT NULL AUTO_INCREMENT COMMENT '路线ID',
                                  `route_name` varchar(50) NOT NULL COMMENT '路线名称',
                                  `robot_id` bigint DEFAULT NULL COMMENT '所属机器人ID',
                                  `map_id` int DEFAULT NULL COMMENT '地图ID',
                                  `point_ids` text COMMENT '点位ID列表(JSON格式)',
                                  `point_count` int DEFAULT '0' COMMENT '点位数量',
                                  `status` char(1) DEFAULT '1' COMMENT '状态（0禁用 1启用）',
                                  `create_by` varchar(64) DEFAULT '' COMMENT '创建者',
                                  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
                                  `update_by` varchar(64) DEFAULT '' COMMENT '更新者',
                                  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
                                  `tenant_id` bigint DEFAULT NULL COMMENT '租户ID',
                                  PRIMARY KEY (`route_id`),
                                  KEY `idx_sys_tour_route_tenant` (`tenant_id`),
                                  KEY `idx_robot_id` (`robot_id`)
) ENGINE=InnoDB AUTO_INCREMENT=24 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='讲解路线表';

-- ----------------------------
-- Records of sys_tour_route
-- ----------------------------

-- ----------------------------
-- Table structure for sys_user
-- ----------------------------
DROP TABLE IF EXISTS `sys_user`;
CREATE TABLE `sys_user`  (
  `user_id` bigint NOT NULL AUTO_INCREMENT COMMENT '用户ID',
  `dept_id` bigint NULL DEFAULT NULL COMMENT '部门ID',
  `user_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户账号',
  `nick_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '用户昵称',
  `user_type` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '00' COMMENT '用户类型（00系统用户）',
  `email` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '用户邮箱',
  `phonenumber` varchar(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '手机号码',
  `sex` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '用户性别（0男 1女 2未知）',
  `avatar` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '头像地址',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '密码',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '账号状态（0正常 1停用）',
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  `login_ip` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '最后登录IP',
  `login_date` datetime NULL DEFAULT NULL COMMENT '最后登录时间',
  `pwd_update_date` datetime NULL DEFAULT NULL COMMENT '密码最后更新时间',
  `create_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`user_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 101 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户信息表' ROW_FORMAT = Dynamic;

