  `pause_snapshot` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `pending_order` int NULL DEFAULT NULL,
  `priority` int NULL DEFAULT NULL,
  `risk_level` int NULL DEFAULT NULL,
  `robot_group_id` bigint NULL DEFAULT NULL,
  `robot_id` bigint NULL DEFAULT NULL,
  `scheduled_time` datetime NULL DEFAULT NULL,
  `status` tinyint NULL DEFAULT NULL,
  `task_type` int NULL DEFAULT NULL,
  `template_id` bigint NULL DEFAULT NULL,
  `terminate_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `create_by` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `create_time` datetime NULL DEFAULT NULL,
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `search_value` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `update_by` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `update_time` datetime NULL DEFAULT NULL,
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `form_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL,
  `global_pending_order` int NULL DEFAULT NULL,
  `tenant_id` bigint NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `task_name_index`(`name` ASC, `tenant_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1070 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

