CREATE TABLE `tm_task_log`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `task_id` bigint NOT NULL COMMENT '关联任务ID',
  `step_id` bigint NULL DEFAULT NULL COMMENT '关联步骤ID（可为空，表示任务级事件）',
  `event_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '事件类型（start/complete/pause/resume/terminate/error/update等）',
