INSERT INTO `tm_template` VALUES (1, '从药房到病房的药品配送流程', '{\"fields\":[{\"id\":\"patientName\",\"label\":\"患者\",\"type\":\"text\",\"required\":true},{\"id\":\"roomNumber\",\"label\":\"病房号\",\"type\":\"text\",\"required\":true},{\"id\":\"medicineList\",\"label\":\"药品清单\",\"type\":\"file\",\"maxCount\":5,\"maxSize\":10,\"accept\":[]}]}', '常规药品配送', '1,2', 0, '{\"steps\":[{\"name\":\"取药\",\"description\":\"在药房领取药品\",\"estimatedTime\":5},{\"name\":\"运输\",\"description\":\"前往目标病房\",\"estimatedTime\":8},{\"name\":\"交付\",\"description\":\"将药品交给护士或患者\",\"estimatedTime\":3}]}', NULL, '2026-03-19 10:31:26', NULL, NULL, 'admin', '2026-03-21 01:03:36', NULL, NULL, NULL);
