INSERT INTO `tm_template` VALUES (3, '全区域安全巡检', '{\"fields\":[{\"id\":\"checkPoints\",\"label\":\"巡检点列表\",\"type\":\"text\",\"required\":true}]}', '夜间巡检', '3', 0, '{\"steps\":[{\"name\":\"启动巡检\",\"description\":\"机器人启动并自检\",\"estimatedTime\":2},{\"name\":\"区域1\",\"description\":\"检查A区门窗\",\"estimatedTime\":20},{\"name\":\"区域2\",\"description\":\"检查B区消防设备\",\"estimatedTime\":20},{\"name\":\"区域3\",\"description\":\"检查C区监控\",\"estimatedTime\":15},{\"name\":\"生成报告\",\"description\":\"汇总巡检结果\",\"estimatedTime\":5}]}', NULL, '2026-03-19 10:31:26', NULL, NULL, NULL, '2026-03-19 10:31:26', NULL, NULL, NULL);
